from collections import Counter


def diagnose_disagreement(paths: list[dict], threshold: float = 0.6) -> str:
    """
    Classify the vote outcome and recommend what to do.
    """
    counts = Counter(p["answer"] for p in paths)
    total  = len(paths)
    top_answer, top_votes = counts.most_common(1)[0]
    share  = top_votes / total
    unique = len(counts)

    if share >= threshold:
        return f"CONFIDENT: '{top_answer}' wins with {share:.0%}. Use majority vote."
    elif unique == total:
        return (
            "ALL_DIFFER: every sample gave a different answer. "
            "Problem likely underspecified or beyond model capability. "
            "Consider rewriting the prompt or using a stronger model."
        )
    elif len(counts) == 2:
        (a1, v1), (a2, v2) = counts.most_common(2)
        return (
            f"TWO_CAMPS: '{a1}' ({v1}) vs '{a2}' ({v2}). "
            "Run a judge call to decide, or increase N to break the tie."
        )
    else:
        return (
            f"SCATTERED: {unique} distinct answers, top share {share:.0%}. "
            "Increase N or run a judge aggregation."
        )


# Simulated path sets
print(diagnose_disagreement([{"answer": "72"}, {"answer": "72"}, {"answer": "72"}, {"answer": "71"}, {"answer": "72"}]))
print(diagnose_disagreement([{"answer": "10"}, {"answer": "12"}, {"answer": "10"}, {"answer": "12"}, {"answer": "11"}]))
print(diagnose_disagreement([{"answer": str(i)} for i in range(7)]))
